import styled from 'styled-components';

export const NavContainer = styled.nav`
background-color:#50A6D8;

hr {
    width:60%;
}


.links__container {
    list-style:none;
}
a {
    color:rgb(255,255,255);
    text-decoration:none;
}

@media only screen and (max-width: 900px) {
    width:100%;

    .links {
        display:flex;
        flex-direction:row;
        align-items:center;
        width:100%;
        gap:1em;
    }

    hr {
        display:none;
    }
}
`
